import { OperatorFunction, pipe, filter, map, of } from "rxjs";

export function filterMap<T, R>(
  pred: (t: T) => boolean,
  proj: (t: T) => R
): OperatorFunction<T, R> {
  return pipe(
    filter<T>(pred),
    map<T, R>(proj)
  );
}

const src$ = of(1, 2, 3, 4, 5);
