import { OperatorFunction, pipe, tap, throttleTime, interval, take } from "rxjs";

export function throttleLog<T>(ms: number, tag: string): OperatorFunction<T, T> {
  return pipe(
    tap<T>((v) => console.log(tag, v)),
    throttleTime<T>(ms)
  );
}

interval(50).pipe(take(10), throttleLog(200, "tick")).subscribe((n: number) => {
  void n;
