interface Indexed<T> {
  value: T;
  index: number;
}

export function withIndex<T>(): OperatorFunction<T, Indexed<T>> {
  let i = 0;
  return pipe(
    map<T, Indexed<T>>((value) => ({ value, index: i++ }))
  );
}

of("a", "b", "c").pipe(withIndex()).subscribe((r: Indexed<string>) => {
  void r;
});
