import { OperatorFunction, pipe, retry, tap, timer, throwError, Observable } from "rxjs";

export function retryTagged<T>(count: number, tag: string): OperatorFunction<T, T> {
  return pipe(
    tap<T>({
      error: (e: unknown) => console.warn(tag, "error", e)
    }),
    retry<T>({
      count,
      delay: (_err: unknown, retryCount: number) => timer(2 ** retryCount * 50)
    })
  );
}

const bad$: Observable<number> = throwError(() => new Error("boom"));
bad$.pipe(retryTagged(2, "task")).subscribe({
  error: (e: unknown) => {
    void e;
  }
});
