import { Observable, of, expand, EMPTY, map, concatMap, toArray } from "rxjs";

interface Page<T> {
  items: T[];
  next: number | null;
}

function fetchPage$(cursor: number): Observable<Page<number>> {
  const next = cursor < 3 ? cursor + 1 : null;
  return of<Page<number>>({ items: [cursor * 10, cursor * 10 + 1], next });
}

const all$: Observable<number[]> = fetchPage$(0).pipe(
  expand((p: Page<number>) => (p.next === null ? EMPTY : fetchPage$(p.next))),
  concatMap((p: Page<number>) => of(...p.items)),
  toArray()
);

all$.subscribe((items: number[]) => {
  void items.length;
});
```

