import { Observable, of, expand, delay, take, map } from "rxjs";

interface PollStep {
  attempt: number;
  waitMs: number;
}

const poll$: Observable<PollStep> = of<PollStep>({ attempt: 0, waitMs: 100 }).pipe(
  expand((s: PollStep) =>
    of<PollStep>({ attempt: s.attempt + 1, waitMs: s.waitMs * 2 }).pipe(delay(s.waitMs))
  ),
  take(5),
  map((s: PollStep) => s)
);

poll$.subscribe((s: PollStep) => {
  void s.attempt;
});
```

`expand` is recursive: it emits every intermediate value AND feeds each one back through the projection, flattening recursively. `mergeMap` only applies the projection to values from the source. Use `expand` for fix-point computations like paginated fetches, tree walks, or retry ladders where each step depends on the previous output.

```typescript
import { Observable, of, from, expand, EMPTY } from "rxjs";

interface Node {
  id: string;
  children: Node[];
}

const root: Node = {
  id: "r",
  children: [
    { id: "a", children: [{ id: "a1", children: [] }] },
    { id: "b", children: [] }
  ]
};

const walk$: Observable<Node> = of(root).pipe(
  expand((n: Node) => (n.children.length > 0 ? from(n.children) : EMPTY))
);

walk$.subscribe((n: Node) => {
  void n.id;
});
```

